const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// ─── Helpers ───────────────────────────────────

function getToken() {
  return localStorage.getItem('cdl_token');
}

function setToken(token) {
  localStorage.setItem('cdl_token', token);
}

function removeToken() {
  localStorage.removeItem('cdl_token');
  localStorage.removeItem('cdl_sesion_activa');
  localStorage.removeItem('cdl_usuario');
}

function getHeaders(conAuth = false) {
